#!/bin/bash
./surfacecast -t v4l2 -d 'libcamerasrc ! video/x-raw,width=1280,height=720,format=BGR,framerate=15/1 ! appsink' -p 'videorate ! videoconvert ! video/x-raw,width=1280,height=720,format=I420,framerate=15/1 ! queue max-size-time=50000000 leaky=downstream ! x264enc bitrate=5000 speed-preset=ultrafast tune=zerolatency key-int-max=15 ! video/x-h264,profile=constrained-baseline,stream-format=byte-stream ! queue ! h264parse config-interval=-1 ! rtph264pay config-interval=1 mtu=1200 ! application/x-rtp,media=video,encoding-name=H264,payload=96 ! udpsink host=carbon.lan port=3000'
